public class Main {
    static <T extends Number> double sum(T a, T b) {
        return a.doubleValue() + b.doubleValue();
    }

    public static void main(String[] args) {
        System.out.println(sum(3, 4));
        System.out.println(sum(2.5, 1.5));
    }
}

