public class Main {
    static <T> T middle(T[] items) {
        return items[items.length / 2];
    }

    public static void main(String[] args) {
        String[] words = { "red", "green", "blue" };
        Integer[] nums = { 10, 20, 30 };
        System.out.println(middle(words));
        System.out.println(middle(nums));
    }
}
